#!/usr/bin/env bash
set -euo pipefail

# Regenerate `tests/fixtures/complex_ptr_statepoint.ll` from the corresponding
# pre-rewrite IR (`complex_ptr_source.ll`) using LLVM 18's
# `rewrite-statepoints-for-gc` pass.

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
NATIVE_JS_DIR="$(cd "${SCRIPT_DIR}/.." && pwd)"
ECMA_RS_DIR="$(cd "${NATIVE_JS_DIR}/.." && pwd)"

FIXTURES_DIR="${NATIVE_JS_DIR}/tests/fixtures"
SOURCE_LL="${FIXTURES_DIR}/complex_ptr_source.ll"
OUT_LL="${FIXTURES_DIR}/complex_ptr_statepoint.ll"

find_llvm_tool() {
  local name="$1"

  # Prefer versioned binaries when present (Ubuntu packages often provide both).
  if command -v "${name}-18" >/dev/null 2>&1; then
    echo "${name}-18"
    return 0
  fi
  if command -v "${name}" >/dev/null 2>&1; then
    echo "${name}"
    return 0
  fi

  echo ""
  return 1
}

fail() {
  echo "error: $*" >&2
  exit 1
}

summarize_version_output() {
  # Avoid `echo "$out" | head -n 1` under `set -o pipefail`: if the consumer
  # exits early, the producer can hit EPIPE/SIGPIPE and make the pipeline fail,
  # which can hide the real version mismatch.
  local out="$1"
  out="${out//$'\r'/}"

  local line1=""
  local line2=""

  if [[ "${out}" == *$'\n'* ]]; then
    line1="${out%%$'\n'*}"
    local rest="${out#*$'\n'}"
    line2="${rest%%$'\n'*}"
  else
    line1="${out}"
  fi

  if [[ -z "${line1}" && -z "${line2}" ]]; then
    printf '%s' "unknown"
  elif [[ -n "${line2}" ]]; then
    printf '%s %s' "${line1}" "${line2}"
  else
    printf '%s' "${line1}"
  fi
}

require_llvm18() {
  local tool="$1"
  local out
  out="$("${tool}" --version 2>/dev/null || true)"

  # Some LLVM builds print the version on line 1 ("Ubuntu LLVM version 18.1.x"),
  # others print it on line 2 ("LLVM (http://llvm.org/):" then "LLVM version 18.1.x").
  if ! grep -Eq 'version 18\.' <<<"${out}"; then
    fail "expected LLVM 18.x (${tool}), got: $(summarize_version_output "${out}")"
  fi
}

OPT="$(find_llvm_tool opt)" || true
LLVM_AS="$(find_llvm_tool llvm-as)" || true
LLC="$(find_llvm_tool llc)" || true
LLVM_READOBJ="$(find_llvm_tool llvm-readobj)" || true

[[ -n "${OPT}" ]] || fail "opt (LLVM 18) not found in PATH"
[[ -n "${LLVM_AS}" ]] || fail "llvm-as (LLVM 18) not found in PATH"
[[ -n "${LLC}" ]] || fail "llc (LLVM 18) not found in PATH"
[[ -n "${LLVM_READOBJ}" ]] || fail "llvm-readobj (LLVM 18) not found in PATH"

require_llvm18 "${OPT}"
require_llvm18 "${LLVM_AS}"
require_llvm18 "${LLC}"
require_llvm18 "${LLVM_READOBJ}"

[[ -f "${SOURCE_LL}" ]] || fail "fixture source not found: ${SOURCE_LL}"

# Keep temp files under target/ so we don't dirty the working tree.
TMP_BASE="${ECMA_RS_DIR}/target"
mkdir -p "${TMP_BASE}"
TMP_DIR="$(mktemp -d "${TMP_BASE}/native-js-complex-ptr-fixture.XXXXXX")"
cleanup() {
  rm -rf "${TMP_DIR}"
}
trap cleanup EXIT

REWRITTEN_LL="${TMP_DIR}/complex_ptr_rewritten.ll"
BC="${TMP_DIR}/complex_ptr.bc"
OBJ="${TMP_DIR}/complex_ptr.o"

# Run with a stable working directory so the `; ModuleID = '...'` line does not
# accidentally capture an absolute path.
(
  cd "${FIXTURES_DIR}"
  "${OPT}" -passes='rewrite-statepoints-for-gc' -S complex_ptr_source.ll -o - >"${REWRITTEN_LL}"
)

{
  cat <<'EOF'
; Generated by LLVM 18:
;   opt-18 -passes='rewrite-statepoints-for-gc' -S complex_ptr_source.ll -o complex_ptr_statepoint.ll
;
; This file is intentionally in the *post*-rewrite form so `native-js` tests can
; compile it directly and validate emitted `.llvm_stackmaps` contents.
;
; The fixture uses `gc "coreclr"` (native-js default strategy) and is expected
; to remain verifier-correct under LLVM 18.
;
; Keep this IR pointer-only: after filtering constants, any stackmap
; `LocationKind::Register` should be treated as a regression (roots must be in
; stack slots).

EOF
  cat "${REWRITTEN_LL}"
} >"${OUT_LL}"

"${LLVM_AS}" "${OUT_LL}" -o "${BC}"
"${LLC}" --fixup-allow-gcptr-in-csr=false --fixup-max-csr-statepoints=0 -filetype=obj "${BC}" -o "${OBJ}"

readobj_sections="$("${LLVM_READOBJ}" --sections "${OBJ}")"
if ! grep -Eq '\.llvm_stackmaps|__llvm_stackmaps' <<<"${readobj_sections}"; then
  echo "${readobj_sections}" >&2
  fail "expected .llvm_stackmaps section in output object: ${OBJ}"
fi

echo "ok: regenerated ${OUT_LL}"
